#include "streamworker.h"
#include <opencv2/opencv.hpp>
#include <opencv2/cudacodec.hpp>
#include <opencv2/core/cuda.hpp>
#include <QMutexLocker>
#include <vector>

namespace {

cv::Ptr<cv::cudacodec::VideoReader> openWithNvdec(const std::string& url, int timeoutMs) {
    // cudacodec::createVideoReader 에 CAP_PROP 파라미터를 넘기면
    // FFmpegVideoSource 가 인식하지 못해 "Unsupported video source" 오류가 발생할 수 있으므로
    // sourceParams 는 빈 벡터로 전달한다.
    const std::vector<int> sourceParams{};

    cv::cudacodec::VideoReaderInitParams params;
    params.allowFrameDrop = true;
    params.udpSource      = false; // RTSP 스트림: false (UDP 직접 소스가 아님)

    cv::Ptr<cv::cudacodec::VideoReader> reader;
    try {
        reader = cv::cudacodec::createVideoReader(url, sourceParams, params);
    } catch (...) {
        return {};
    }

    if (!reader.empty())
        reader->set(cv::cudacodec::BGR);
    return reader;
}

bool openWithFallback(cv::VideoCapture& cap, const std::string& url, int timeoutMs) {
    cap.set(cv::CAP_PROP_HW_ACCELERATION, cv::VIDEO_ACCELERATION_NONE);
    cap.set(cv::CAP_PROP_OPEN_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_READ_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_BUFFERSIZE, 1);
    if (cap.open(url, cv::CAP_FFMPEG)) return true;

    return cap.open(url);
}

} // namespace

StreamWorker::StreamWorker(int cellId, const QString& url, QObject* parent)
    : QThread(parent), m_cellId(cellId), m_url(url) {}

void StreamWorker::stop() {
    m_running = false;
    requestInterruption();
}

bool StreamWorker::takeLatestFrame(QImage& outFrame) {
    QMutexLocker lock(&m_frameMutex);
    if (m_latestFrame.isNull()) return false;
    outFrame = m_latestFrame;
    m_latestFrame = QImage();
    m_notifyPending.store(false, std::memory_order_release);
    return true;
}

void StreamWorker::run() {
    constexpr int READ_TIMEOUT_MS    = 2000;
    constexpr int RECONNECT_DELAY_MS = 3000;

    const auto publishFrame = [this](const cv::Mat& bgrFrame) {
        cv::Mat rgbFrame;
        cv::cvtColor(bgrFrame, rgbFrame, cv::COLOR_BGR2RGB);

        QImage img(rgbFrame.data, rgbFrame.cols, rgbFrame.rows,
                   static_cast<int>(rgbFrame.step),
                   QImage::Format_RGB888);
        {
            QMutexLocker lock(&m_frameMutex);
            m_latestFrame = img.copy();
        }

        // UI 이벤트 큐에는 셀당 프레임 알림 1개만 유지하고, 나머지는 최신 프레임으로 덮어쓴다.
        if (!m_notifyPending.exchange(true, std::memory_order_acq_rel))
            emit frameReady(m_cellId);
    };

    while (!isInterruptionRequested()) {
        emit statusChanged(m_cellId, "연결 중...");

        const std::string url = m_url.toStdString();
        bool usingNvdec = false;

        emit statusChanged(m_cellId, "NVDEC 연결 시도...");
        try {
            auto gpuReader = openWithNvdec(url, READ_TIMEOUT_MS);
            if (!gpuReader.empty()) {
                usingNvdec = true;
                emit statusChanged(m_cellId, m_url + " [NVDEC]");

                cv::cuda::GpuMat gpuFrame;
                cv::Mat cpuFrame;
                while (!isInterruptionRequested()) {
                    if (!gpuReader->nextFrame(gpuFrame) || gpuFrame.empty()) {
                        emit statusChanged(m_cellId, "스트림 끊김 – 재연결...");
                        break;
                    }

                    gpuFrame.download(cpuFrame);
                    if (cpuFrame.empty()) {
                        emit statusChanged(m_cellId, "NVDEC 프레임 변환 실패 – 재연결...");
                        break;
                    }

                    publishFrame(cpuFrame);
                }
            }
        } catch (const cv::Exception& exception) {
            std::cerr << "\nERROR: " << exception.what() << std::endl;
            usingNvdec = false;
        }

        if (!usingNvdec && !isInterruptionRequested()) {
            cv::VideoCapture cap;
            emit statusChanged(m_cellId, "NVDEC 실패 - 일반 디코더 재시도...");
            if (!openWithFallback(cap, url, READ_TIMEOUT_MS)) {
                emit statusChanged(m_cellId, "연결 실패 – 재시도 중...");
            } else {
                emit statusChanged(m_cellId, m_url);

                cv::Mat frame;
                while (!isInterruptionRequested()) {
                    if (!cap.read(frame) || frame.empty()) {
                        emit statusChanged(m_cellId, "스트림 끊김 – 재연결...");
                        break;
                    }

                    publishFrame(frame);
                }
            }

            cap.release();
        }

        // Wait before reconnect
        for (int i = 0; i < (RECONNECT_DELAY_MS / 100) && !isInterruptionRequested(); ++i)
            msleep(100);
    }
}

#include "streamworker.h"
#include <opencv2/opencv.hpp>
#include <opencv2/cudacodec.hpp>
#include <opencv2/core/cuda.hpp>
#include <QMutexLocker>
#include <vector>

namespace {

// cudacodec::FFmpegVideoSource 는 내부적으로 자체 avformat_open_input() 을 호출하며
// AVDictionary 옵션(rtsp_transport, timeout 등)을 전달할 수단이 없다.
// 따라서 rtsp:// / http:// 등 네트워크 URL 에는 사용할 수 없다.
// → 로컬 파일 경로일 때만 시도한다.
bool isLocalFile(const std::string& url) {
    // 스킴이 없거나 드라이브 문자(C:\...)로 시작하면 로컬 파일로 판단
    const std::string lower = [&]{
        std::string s = url;
        std::transform(s.begin(), s.end(), s.begin(), ::tolower);
        return s;
    }();
    if (lower.rfind("rtsp://",  0) == 0) return false;
    if (lower.rfind("rtmp://",  0) == 0) return false;
    if (lower.rfind("http://",  0) == 0) return false;
    if (lower.rfind("https://", 0) == 0) return false;
    if (lower.rfind("udp://",   0) == 0) return false;
    if (lower.rfind("tcp://",   0) == 0) return false;
    return true;
}

cv::Ptr<cv::cudacodec::VideoReader> openWithNvdec(const std::string& url) {
    // 네트워크 스트림은 cudacodec::FFmpegVideoSource 가 AVOptions 를 지원하지 않아
    // "Unsupported video source" 오류가 발생하므로 즉시 포기한다.
    if (!isLocalFile(url))
        return {};

    cv::cudacodec::VideoReaderInitParams params;
    params.allowFrameDrop = true;

    cv::Ptr<cv::cudacodec::VideoReader> reader;
    try {
        reader = cv::cudacodec::createVideoReader(url, {}, params);
    } catch (...) {
        return {};
    }

    if (!reader.empty())
        reader->set(cv::cudacodec::BGR);
    return reader;
}

// VideoCapture 기반 오픈:
//   1순위 – D3D11/DXVA2 GPU 가속 (RTSP 에서도 동작)
//   2순위 – CPU 소프트웨어 디코딩
bool openWithFallback(cv::VideoCapture& cap, const std::string& url, int timeoutMs) {
    // GPU 가속 시도 (D3D11 / DXVA2 / VideoToolbox 등 플랫폼 최적 선택)
    cap.set(cv::CAP_PROP_HW_ACCELERATION, cv::VIDEO_ACCELERATION_ANY);
    cap.set(cv::CAP_PROP_OPEN_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_READ_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_BUFFERSIZE, 1);
    if (cap.open(url, cv::CAP_FFMPEG)) return true;

    // GPU 가속 실패 시 소프트웨어 디코딩으로 재시도
    cap.set(cv::CAP_PROP_HW_ACCELERATION, cv::VIDEO_ACCELERATION_NONE);
    cap.set(cv::CAP_PROP_OPEN_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_READ_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_BUFFERSIZE, 1);
    if (cap.open(url, cv::CAP_FFMPEG)) return true;

    return cap.open(url);
}

} // namespace

StreamWorker::StreamWorker(int cellId, const QString& url, QObject* parent)
    : QThread(parent), m_cellId(cellId), m_url(url) {}

void StreamWorker::stop() {
    m_running = false;
    requestInterruption();
}

bool StreamWorker::takeLatestFrame(QImage& outFrame) {
    QMutexLocker lock(&m_frameMutex);
